Dos formas de vaciar una lista:

```javascript
// Forma 1: innerHTML vacio (mas simple)
btnVaciar.addEventListener('click', () => {
  lista.innerHTML = '';
});

// Forma 2: replaceChildren (metodo moderno)
btnVaciar.addEventListener('click', () => {
  lista.replaceChildren();
});

// Forma 3: while loop (clasico)
while (lista.firstChild) {
  lista.removeChild(lista.firstChild);
}
```
Recomendacion: innerHTML = '' es la mas usada.

Funcion auxiliar para añadir mensajes a un log:

const logEvents = document.getElementById('log-events');

```javascript
function añadirAlLog(texto) {
  const li = document.createElement('li');
  li.textContent = texto;
  logEvents.appendChild(li);
}

// Uso en listeners:
contenedor.addEventListener('click', () => {
  añadirAlLog('Click en el contenedor');
});

boton.addEventListener('click', () => {
  añadirAlLog('Click en el boton');
});

// El log muestra el historial de eventos.
```

Patron para cambiar comportamiento dinamicamente:

```javascript
// Version SIN stopPropagation
function clickSinStop(e) {
  añadirAlLog('Click en boton (propagacion activa)');
}

// Version CON stopPropagation
function clickConStop(e) {
  e.stopPropagation();
  añadirAlLog('Click en boton (stopPropagation)');
}

// Alternar entre versiones
btnActivar.addEventListener('click', () => {
  boton.removeEventListener('click', clickSinStop);
  boton.addEventListener('click', clickConStop);
});

btnDesactivar.addEventListener('click', () => {
  boton.removeEventListener('click', clickConStop);
  boton.addEventListener('click', clickSinStop);
});
```
IMPORTANTE: Las funciones deben ser nombradas.

Slide 5 - boton dentro de contenedor:

```javascript
// Listener en el contenedor (siempre activo)
contenedor.addEventListener('click', () => {
  añadirAlLog('Click en CONTENEDOR');
});

// Boton interno - version sin detener
function clickBotonNormal(e) {
  añadirAlLog('Click en BOTON (sin stop)');
  // El evento sube al contenedor
}

// Boton interno - version con stopPropagation
function clickBotonStop(e) {
  e.stopPropagation();
  añadirAlLog('Click en BOTON (con stop)');
  // El evento NO sube al contenedor
}
```
RESULTADOS:
- Sin stop: aparecen dos mensajes (boton + contenedor)
- Con stop: aparece solo el del boton

Patron con variable de estado:

let usandoStop = false;  // bandera/flag

```javascript
// Activar stopPropagation
btnActivar.addEventListener('click', () => {
  if (!usandoStop) {  // solo si no esta activo
    boton.removeEventListener('click', clickSinStop);
    boton.addEventListener('click', clickConStop);
    usandoStop = true;
    añadirAlLog('StopPropagation activado');
  }
});

// Desactivar stopPropagation
btnDesactivar.addEventListener('click', () => {
  if (usandoStop) {  // solo si esta activo
    boton.removeEventListener('click', clickConStop);
    boton.addEventListener('click', clickSinStop);
    usandoStop = false;
    añadirAlLog('StopPropagation desactivado');
  }
});
```
